        putExtra(Intent.EXTRA_TEXT, shareText)
    }
    context.startActivity(Intent.createChooser(intent, chooserTitle))
}

private fun shareVerdict(context: Context, sender: String, verdict: DeepCheckVerdict, chooserTitle: String) {
